from flask import Flask, request, jsonify
from nltk.tokenize import word_tokenize

app = Flask(__name__)

@app.route('/tokenize', methods=['POST'])
def tokenize():
    data = request.get_json()

    text = data.get("text", "")

    tokens = word_tokenize(text)

    return jsonify({
        "tokens": tokens
    })

if __name__ == "__main__":
    app.run(debug=True)

